func NewConsumerGroupMetrics(meter metric.Meter) (*ConsumerGroupMetrics, error) {
	var err error
	m := &ConsumerGroupMetrics{}
	m.State, err = meter.Int64Gauge(
		"kafka.consumer_group.state",
		metric.WithDescription("Local consumer group handler's state"),
	)
	if err != nil {
		return nil, fmt.Errorf("failed to create metric: kafka.consumer_group.state: %w", err)
	}
	return m, nil
}

func (m *ConsumerGroupMetrics) Add(ctx context.Context, stats *stats.ConsumerGroupStats, attrs ...attribute.KeyValue) {
	if stats == nil {
		return
	}
	m.State.Record(ctx, stats.State.Int64(), metric.WithAttributes(attrs...))
}

type BrokerState string

const (
	BrokerStateUnknown BrokerState = "unknown"
	BrokerStateUp      BrokerState = "up"
)

func (s *BrokerState) UnmarshalJSON(data []byte) error {
	var value string
	if err := json.Unmarshal(data, &value); err != nil {
		return fmt.Errorf("failed to unmarshal value: %s", data)
	}
	switch strings.ToLower(strings.TrimSpace(value)) {
	case "up":
		*s = BrokerStateUp
	default:
		*s = BrokerStateUnknown
	}
	return nil
}

func (s BrokerState) Int64() int64 {
	switch s {
	case BrokerStateUp:
		return 6
	default:
		return -1
	}
}
